import{_ as o,o as c,c as d,a2 as t}from"./chunks/framework.BKG_UbFK.js";const h=JSON.parse('{"title":"البنية المعمارية","description":"","frontmatter":{},"headers":[],"relativePath":"ar/guide/architecture.md","filePath":"ar/guide/architecture.md"}'),r={name:"ar/guide/architecture.md"};function a(l,e,i,s,n,_){return c(),d("div",null,[...e[0]||(e[0]=[t('<h1 id="البنية-المعمارية" tabindex="-1">البنية المعمارية <a class="header-anchor" href="#البنية-المعمارية" aria-label="Permalink to &quot;البنية المعمارية&quot;">​</a></h1><h2 id="كيف-تعمل-عملية-التحليل-resolution" tabindex="-1">كيف تعمل عملية التحليل (Resolution) <a class="header-anchor" href="#كيف-تعمل-عملية-التحليل-resolution" aria-label="Permalink to &quot;كيف تعمل عملية التحليل (Resolution)&quot;">​</a></h2><p><code>resolveFor()</code> هي جوهر التفويض السياقي في Clearance - انظر <a href="/clearance-docs/ar/features/contextual-authorization.html">التفويض السياقي</a> للاطلاع على واجهة الـ API الكاملة. تدمج ثلاثة مصادر، بترتيب الأولوية التالي:</p><ol><li><strong>منح الأدوار السياقية</strong> - الصلاحيات من الأدوار التي يحملها المستخدم تحديداً ضمن هذا السياق (<code>clr_role_ctx</code>).</li><li><strong>منح الأدوار العامة</strong> - الصلاحيات من أدوار Spatie المُعيَّنة عالمياً للمستخدم (بحيث يُلبّي <code>super_admin</code> وأدوار عامة أخرى شرط <code>canIn()</code> لأي سياق).</li><li><strong>التجاوزات الخاصة بكل سياق</strong> (<code>clr_ctx_overrides</code>) - <code>forced_on</code> تضيف صلاحية فوق ما سبق؛ <code>forced_off</code> تُزيلها، حتى لو كانت الصلاحية ممنوحة من دور عام. الرفض يفوز دائماً.</li></ol><div class="warning custom-block"><p class="custom-block-title">الرفض يفوز دائماً</p><p>تتجاوز <code>forced_off</code> أي صلاحية ممنوحة من دور عام أو من منح دور سياقي. لا توجد وسيلة &quot;لتخطّي&quot; تجاوز <code>forced_off</code> لنفس المستخدم/الصلاحية/السياق سوى إزالته.</p></div><h2 id="قاعدة-البيانات" tabindex="-1">قاعدة البيانات <a class="header-anchor" href="#قاعدة-البيانات" aria-label="Permalink to &quot;قاعدة البيانات&quot;">​</a></h2><p>تمتلك Clearance 6 جداول ولا تُعدّل أبداً جداول Spatie الأساسية (<code>roles</code>، <code>permissions</code>، <code>model_has_roles</code>، <code>model_has_permissions</code>، <code>role_has_permissions</code>). جميع المفاتيح الخارجية (FKs) المشيرة إلى <code>roles.id</code>/<code>permissions.id</code> تتسلسل عند الحذف (cascade on delete) ما لم يُذكر خلاف ذلك؛ ولا تحتوي جداول Spatie على أي مفاتيح خارجية تشير مرة أخرى إلى <code>clr_*</code>.</p><table tabindex="0"><thead><tr><th>الجدول</th><th>الأعمدة الأساسية</th></tr></thead><tbody><tr><td><code>clr_meta</code></td><td><code>subject_type</code>، <code>subject_key</code> (فريد معاً) - <code>display_name</code>، <code>description</code>، <code>icon_svg</code>، <code>color</code> - بيانات عرض وصفية لدور أو حارس</td></tr><tr><td><code>clr_role_meta</code></td><td><code>role_id</code> (فريد، FK -&gt; <code>roles</code>) - <code>is_locked</code>، <code>scope</code> (<code>global</code>|<code>contextual</code>)، <code>context_types</code> (json) - <code>parent_role_id</code> (FK اختياري -&gt; <code>roles</code>، <code>ON DELETE SET NULL</code>) - الدور السقفي</td></tr><tr><td><code>clr_guards</code></td><td><code>name</code> (فريد)، <code>driver</code>، <code>provider</code> - الحراس المُدارة عبر اللوحة</td></tr><tr><td><code>clr_settings</code></td><td><code>key</code> (فريد)، <code>value</code> - مخزن مفتاح/قيمة وقت التشغيل (الدور الافتراضي، إلخ)</td></tr><tr><td><code>clr_role_ctx</code></td><td><code>user_id</code>، <code>role_id</code> (FK -&gt; <code>roles</code>)، <code>context_type</code>، <code>context_id</code> - تعيينات أدوار سياقية، فريدة لكل <code>(user, role, context_type, context_id)</code></td></tr><tr><td><code>clr_ctx_overrides</code></td><td><code>user_id</code>، <code>role_id</code> (FK -&gt; <code>roles</code>)، <code>permission_id</code> (FK -&gt; <code>permissions</code>)، <code>context_type</code>، <code>context_id</code>، <code>type</code> (<code>forced_on</code>|<code>forced_off</code>) - تجاوزات صلاحيات خاصة بكل مستخدم وكل سياق</td></tr></tbody></table><h2 id="لا-تمسّ-جداول-spatie-أبداً" tabindex="-1">لا تمسّ جداول Spatie أبداً <a class="header-anchor" href="#لا-تمسّ-جداول-spatie-أبداً" aria-label="Permalink to &quot;لا تمسّ جداول Spatie أبداً&quot;">​</a></h2><p>صُمّمت Clearance لتعمل جنباً إلى جنب مع <code>spatie/laravel-permission</code>، لا لتحل محلها. كل سجل <code>Role</code> و<code>Permission</code> تُنشئه أو تُعدّله لوحة Clearance هو نموذج Spatie حقيقي، مخزّن في جداول Spatie الخاصة بها. لا تُشغّل Clearance أبداً ترحيلاً (migration) يضيف عموداً إلى، أو يكتب مفتاحاً خارجياً من، أي من <code>roles</code>، أو <code>permissions</code>، أو <code>model_has_roles</code>، أو <code>model_has_permissions</code>، أو <code>role_has_permissions</code>.</p><p>جميع بيانات Clearance الخاصة - بيانات العرض الوصفية، ونطاق الأدوار وأسقفها، والتعيينات السياقية، والتجاوزات الخاصة بكل سياق، وتعريفات الحراس، والإعدادات - تعيش حصرياً في جداول <code>clr_*</code> الستة أعلاه. هذا يعني:</p><ul><li>إلغاء تثبيت Clearance لا يُعرّض أبداً بيانات الأدوار/الصلاحيات الموجودة في Spatie للخطر.</li><li>أي كود يقرأ بالفعل نماذج أو جداول Spatie مباشرة يستمر في العمل دون تعديل.</li><li>ميزات Clearance السياقية والسقفية هي طبقات إضافية بحتة تُحلَّل وقت الاستعلام (عبر <code>resolveFor()</code> و<code>RoleService</code>)، وليست مدمجة في مخطط (schema) Spatie.</li></ul><h2 id="ذو-صلة" tabindex="-1">ذو صلة <a class="header-anchor" href="#ذو-صلة" aria-label="Permalink to &quot;ذو صلة&quot;">​</a></h2><ul><li><a href="/clearance-docs/ar/features/contextual-authorization.html">التفويض السياقي</a> - <code>canIn()</code>، <code>hasRoleIn()</code>، توجيهات Blade، <code>ContextService</code></li><li><a href="/clearance-docs/ar/features/roles.html">الأدوار</a> - نطاق الأدوار وأسقفها، <code>RoleService::setParent()</code></li><li><a href="/clearance-docs/ar/guide/migration.html">الترحيل</a> - ملء <code>clr_meta</code>/<code>clr_role_meta</code>/<code>clr_guards</code> على تثبيت Spatie موجود مسبقاً</li><li><a href="/clearance-docs/ar/guide/security.html">الأمان</a> - كيف يمنع نموذج السقف والتجاوز تصعيد الصلاحيات</li></ul>',14)])])}const u=o(r,[["render",a]]);export{h as __pageData,u as default};
